				// Lookup the hearing type in ref data from the code that is stored in value
				var xpathCode = REF_DATA_XPATH + "/Courts/Court[Id = " + id + "]/Code";		
				var xpathName = REF_DATA_XPATH + "/Courts/Court[Id = " + id + "]/Name";		
